import java.util.*;

public class Solution {
    public static long run(byte[] src, byte[] dst, int width, int height, int iters) {
        int pixels = width * height;
        int totalBytes = pixels * 4;
        byte[] out = new byte[totalBytes];
        long hash = 0;

        for (int iter = 0; iter < iters; iter++) {
            for (int i = 0; i < pixels; i++) {
                int base = i * 4;
                int a = src[base + 3] & 0xFF;
                int invA = 255 - a;

                // Blend R
                int r = (src[base] & 0xFF) * a + (dst[base] & 0xFF) * invA;
                out[base] = (byte) ((r + 127) / 255);

                // Blend G
                int g = (src[base + 1] & 0xFF) * a + (dst[base + 1] & 0xFF) * invA;
                out[base + 1] = (byte) ((g + 127) / 255);

                // Blend B
                int b = (src[base + 2] & 0xFF) * a + (dst[base + 2] & 0xFF) * invA;
                out[base + 2] = (byte) ((b + 127) / 255);

                // Alpha is always 255
                out[base + 3] = (byte) 255;
            }

            // Calculate checksum for the current iteration
            long currentHash = 1469598103934665603L;
            for (int i = 0; i < totalBytes; i++) {
                currentHash ^= (out[i] & 0xFFL);
                currentHash *= 1099511628211L;
            }
            hash = currentHash;
        }
        return hash;
    }
}
